for fn in ['model.py','train_clip.py','train.py','train_pseudo.py']:
    print(f'===== {fn} =====')
    p=Path(fn)
    if not p.exists():
        print('MISSING')
        continue
    lines=p.read_text().splitlines()
    for i,l in enumerate(lines[:260],1):
        print(f'{i:03d}: {l}')
    if len(lines)>260:
        print(f'... truncated {len(lines)-260} more lines')
print('===== checkpoint metadata =====')
import torch, glob
for ck in glob.glob('checkpoints/*.pt'):
    try:
        obj=torch.load(ck,map_location='cpu')
        if isinstance(obj,dict):
            keys=list(obj.keys())
            meta={k:obj.get(k) for k in ['arch','num_classes','img_size','epoch','best_val_acc_noisy','ema'] if k in obj}
            if 'ensemble' in obj: meta={'ensemble':obj.get('ensemble'),'weights':obj.get('weights')}
            print(ck, meta, 'keys', keys[:8])
        else:
            print(ck, type(obj))
    except Exception as e:
        print(ck, 'ERR', e)
